mapper.select:
SELECT a.*, b.brand_name AS brandName, c.realname AS businessName FROM cooperation_info a LEFT JOIN kol_brand b ON a.brand_id = b.id LEFT JOIN sys_user c ON a.business_id = c.id WHERE 1 = 1
AND a.brand_id = #{cooperationInfo.brandId}
AND a.business_id = #{cooperationInfo.businessId}
AND a.product_plan LIKE CONCAT('%', #{cooperationInfo.productPlan}, '%')
AND a.customer_acquisition_method LIKE CONCAT('%', #{cooperationInfo.customerAcquisitionMethod}, '%')
AND a.latest_cooperation_dynamic LIKE CONCAT('%', #{cooperationInfo.latestCooperationDynamic}, '%')
AND a.project_status = #{cooperationInfo.projectStatus}
AND a.cooperation_date = #{cooperationInfo.cooperationDate}
